set "edgedir=%ProgramFiles(x86)%\Microsoft\Edge\Application"
if not exist "%edgedir%" set "edgedir=%ProgramFiles%\Microsoft\Edge\Application"

for /f "delims=" %%v in ('dir "%edgedir%" /b /ad 2^>nul ^| findstr /r "^[0-9]"') do (
    set "edgever=%%v"
)

if defined edgever (
    "%edgedir%\%edgever%\Installer\setup.exe" --uninstall --system-level --verbose-logging --force-uninstall
)

reg delete "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths\msedge.exe" /f >nul 2>&1
reg delete "HKCU\SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths\msedge.exe" /f >nul 2>&1
reg add "HKLM\SOFTWARE\Policies\Microsoft\EdgeUpdate" /v "InstallDefault" /t REG_DWORD /d 0 /f >nul 2>&1
reg add "HKLM\SOFTWARE\Policies\Microsoft\Edge" /v "HideFirstRunExperience" /t REG_DWORD /d 1 /f >nul 2>&1

powershell -Command "Get-AppxPackage -AllUsers *MicrosoftEdge* | Where-Object {$_.Name -notlike '*WebView*'} | Remove-AppxPackage -AllUsers" >nul 2>&1

exit /b

$startupPaths = @(
    "HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Run"
    "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Run"
    "HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Run"
)

$keepList = @(
    "SecurityHealth"
)

foreach ($path in $startupPaths) {
    if (Test-Path $path) {
        $entries = Get-ItemProperty -Path $path -ErrorAction SilentlyContinue
        $entries.PSObject.Properties | Where-Object {
            $_.MemberType -eq 'NoteProperty' -and
            $_.Name -notlike 'PS*' -and
            $_.Name -notin $keepList
        } | ForEach-Object {
            Remove-ItemProperty -Path $path -Name $_.Name -Force -ErrorAction SilentlyContinue
        }
    }
}

$regTweaks = @{
    "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer" = @{
        "StartupDelayInMSec" = 0
    }
    "HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\Serialize" = @{
        "StartupDelayInMSec" = 0
    }
    "HKLM:\SYSTEM\CurrentControlSet\Control" = @{
        "WaitToKillServiceTimeout" = "1000"
    }
    "HKCU:\Control Panel\Desktop" = @{
        "AutoEndTasks" = "1"
    }
    "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Multimedia\SystemProfile" = @{
        "SystemResponsiveness" = 10
        "NetworkThrottlingIndex" = 4294967295
    }
    "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Multimedia\SystemProfile\Tasks\Games" = @{
        "GPU Priority" = 8
        "Priority" = 6
        "Scheduling Category" = "High"
        "SFIO Priority" = "High"
    }
}

foreach ($path in $regTweaks.Keys) {
    if (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
    foreach ($name in $regTweaks[$path].Keys) {
        $value = $regTweaks[$path][$name]
        if ($value -is [int]) {
            Set-ItemProperty -Path $path -Name $name -Value $value -Type DWord -Force
        } else {
            Set-ItemProperty -Path $path -Name $name -Value $value -Type String -Force
        }
    }
}

$tasksTweaks = @(
    "\Microsoft\Windows\Application Experience\Microsoft Compatibility Appraiser"
    "\Microsoft\Windows\Application Experience\ProgramDataUpdater"
    "\Microsoft\Windows\Application Experience\StartupAppTask"
    "\Microsoft\Windows\Defrag\ScheduledDefrag"
    "\Microsoft\Windows\DiskDiagnostic\Microsoft-Windows-DiskDiagnosticDataCollector"
    "\Microsoft\Windows\Power Efficiency Diagnostics\AnalyzeSystem"
    "\Microsoft\Windows\Wdi\ResolutionHost"
)

foreach ($task in $tasksTweaks) {
    Disable-ScheduledTask -TaskPath (Split-Path $task) -TaskName (Split-Path $task -Leaf) -ErrorAction SilentlyContinue
}

exit 0

@echo off
powershell -ExecutionPolicy Bypass -Command "$i = Get-ItemProperty 'HKLM:\Software\Microsoft\Windows\CurrentVersion\Uninstall\*','HKCU:\Software\Microsoft\Windows\CurrentVersion\Uninstall\*','HKLM:\Software\Wow6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*' -ErrorAction SilentlyContinue | Where-Object { $_.DisplayName -like '*Brave*' }; if ($i) { exit 1 } else { exit 0 }"
if %errorlevel% equ 1 (
    echo Brave ja esta instalado.
    timeout /t 3 /nobreak >nul
    exit /b 0
)

:waitnet
ping -n 1 -w 1000 8.8.8.8 >nul 2>&1 || (timeout /t 5 /nobreak >nul && goto waitnet)

powershell -ExecutionPolicy Bypass -Command "$client = New-Object System.Net.WebClient; $client.DownloadFile('https://referrals.brave.com/latest/BraveBrowserSetup-BRV010.exe', \"$env:TEMP\BraveSetup.exe\")"
if %errorlevel% neq 0 (
    echo ERRO: Download falhou com codigo %errorlevel%.
    timeout /t 5 /nobreak >nul
    exit /b %errorlevel%
)

if not exist "%TEMP%\BraveSetup.exe" (
    echo ERRO: Arquivo nao encontrado apos download.
    timeout /t 5 /nobreak >nul
    exit /b 1
)

start /wait "" "%TEMP%\BraveSetup.exe" --silent --install
if %errorlevel% neq 0 (
    echo ERRO: Instalacao falhou com codigo %errorlevel%.
    timeout /t 5 /nobreak >nul
    exit /b %errorlevel%
)

del /f /q "%TEMP%\BraveSetup.exe"
echo Brave instalado com sucesso.
timeout /t 3 /nobreak >nul
exit /b

